    {
      "id": "PROP-0001",
      "text": "The secp256k1 signature recovery in recover_sender must validate that 0 < r < SECP256K1N; any transaction with r == 0 or r >= SECP256K1N must be rejected before public key recovery.",
      "type": "pre-condition",
      "source_assumption_id": "asm-001",
      "source_invariant_id": "INV-001 (SG-005/transactions)",
      "covers": {
        "primary_element": "SG-005",
        "nodes": ["actor-eoa", "actor-transaction-processor"],
